import { Component, OnInit } from '@angular/core';
import { RoomTransferService } from '../../services/room-transfer.service';
import { AuthService } from '../../services/auth.service';

@Component({
  selector: 'app-room-transfers',
  templateUrl: './room-transfers.component.html',
  styleUrls: ['./room-transfers.component.css']
})
export class RoomTransfersComponent implements OnInit {
  requests: any[] = [];
  currentUser: any;

  constructor(private transferService: RoomTransferService, private authService: AuthService) {}

  ngOnInit() {
    this.currentUser = this.authService.getCurrentUser();
    this.loadRequests();
  }

  loadRequests() {
    if (this.currentUser.role === 'STUDENT') {
      this.transferService.getTransferRequestsByStudent(this.currentUser.id).subscribe(data => this.requests = data);
    } else {
      this.transferService.getAllTransferRequests().subscribe(data => this.requests = data);
    }
  }
}
<div class="content-wrapper">
  <div class="container-fluid">
    <h2 class="mb-4">Room Transfer Requests</h2>

    <div class="table-responsive">
      <table class="table">
        <thead>
          <tr>
            <th>ID</th>
            <th>Student</th>
            <th>Current Room</th>
            <th>Requested Room</th>
            <th>Reason</th>
            <th>Status</th>
            <th>Created</th>
          </tr>
        </thead>
        <tbody>
          <tr *ngFor="let req of requests">
            <td>{{ req.id }}</td>
            <td>{{ req.studentName }}</td>
            <td>{{ req.currentRoomNumber }}</td>
            <td>{{ req.requestedRoomNumber }}</td>
            <td>{{ req.reason }}</td>
            <td><span class="badge" [ngClass]="{'bg-success': req.status === 'APPROVED', 'bg-danger': req.status === 'REJECTED', 'bg-warning': req.status === 'PENDING'}">
              {{ req.status }}</span></td>
            <td>{{ req.createdAt | date:'short' }}</td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
</div>
